286→/**
287→ * Polls until an intent reaches the target status or times out.
288→ * Used to wait for async evaluation pipeline (SurrealQL EVENT -> evaluate -> status update).
289→ */
290→export async function waitForIntentStatus(
291→  surreal: Surreal,
292→  intentId: string,
293→  targetStatus: IntentStatus | IntentStatus[],
294→  timeoutMs = 30_000,
295→): Promise<IntentStatus> {
296→  const targets = Array.isArray(targetStatus) ? targetStatus : [targetStatus];
297→  const start = Date.now();
298→
299→  while (Date.now() - start < timeoutMs) {
300→    const current = await getIntentStatus(surreal, intentId);
301→    if (targets.includes(current)) {
302→      return current;
303→    }
304→    await Bun.sleep(250);
305→  }
306→
307→  const finalStatus = await getIntentStatus(surreal, intentId);
308→  throw new Error(
309→    `Intent ${intentId} did not reach ${targets.join("|")} within ${timeoutMs}ms. ` +
310→    `Current status: ${finalStatus}`,
311→  );
312→}
