 81→function toTransition(
 82→  routing: ReturnType<typeof routeByRisk>,
 83→  evaluationRecord: EvaluatedIntent["evaluation"],
 84→): TransitionPlan {
 85→  switch (routing.route) {
 86→    case "auto_approve":
 87→      return {
 88→        status: "authorized",
 89→        updateFields: { evaluation: evaluationRecord },
 90→      };
 91→    case "veto_window":
 92→      return {
 93→        status: "pending_veto",
 94→        updateFields: { evaluation: evaluationRecord, veto_expires_at: routing.expires_at },
 95→        vetoExpiresAt: routing.expires_at,
 96→      };
 97→    case "reject":
 98→      return {
 99→        status: "vetoed",
100→        updateFields: { evaluation: evaluationRecord },
101→      };
102→  }
103→}
