105→export async function evaluatePendingIntent(
106→  intentId: string,
107→  deps: EvaluatePendingIntentDeps,
108→  options?: EvaluatePendingIntentOptions,
109→): Promise<EvaluatePendingIntentResult> {
110→  const intent = options?.intent ?? await getIntentById(deps.surreal, intentId);
111→  if (!intent) {
112→    return { ok: false, error: "Intent not found", httpStatus: 404 };
113→  }
114→
115→  if (intent.status !== "pending_auth") {
116→    return {
117→      ok: false,
118→      error: `Intent is in '${intent.status}' status, expected 'pending_auth'`,
119→      httpStatus: 409,
120→    };
121→  }
122→
123→  const identityId = resolveRecordId("identity", intent.requester);
124→  const workspaceRecord = resolveRecordId("workspace", intent.workspace);
125→  const intentRecord = new RecordId("intent", intentId);
126→
127→  const [identityRows] = await deps.surreal.query<[Array<{ type?: string; role?: string; name?: string }>]>(
128→    `SELECT type, role, name FROM $identity;`,
129→    { identity: identityId },
130→  );
131→  const identityInfo = identityRows[0];
132→
133→  const llmEvaluator = deps.llmEvaluator
134→    ?? (deps.extractionModel ? createLlmEvaluator(deps.extractionModel) : undefined);
135→  if (!llmEvaluator) {
136→    return { ok: false, error: "Missing evaluator model", httpStatus: 500 };
137→  }
138→
139→  // Read workspace evidence enforcement mode, minimum evidence age, and maturity threshold
140→  let evidenceEnforcementMode: EvidenceEnforcementMode = "bootstrap";
141→  let minEvidenceAgeMinutes: number | undefined;
142→  try {
143→    const [wsRows] = await deps.surreal.query<[Array<{
144→      evidence_enforcement?: string;
145→      min_evidence_age_minutes?: number;
146→      evidence_enforcement_threshold?: { min_decisions?: number; min_tasks?: number };
147→    }>]>(
148→      `SELECT evidence_enforcement, min_evidence_age_minutes, evidence_enforcement_threshold FROM $ws;`,
149→      { ws: workspaceRecord },
150→    );

140→  let evidenceEnforcementMode: EvidenceEnforcementMode = "bootstrap";
141→  let minEvidenceAgeMinutes: number | undefined;
142→  try {
143→    const [wsRows] = await deps.surreal.query<[Array<{
144→      evidence_enforcement?: string;
145→      min_evidence_age_minutes?: number;
146→      evidence_enforcement_threshold?: { min_decisions?: number; min_tasks?: number };
147→    }>]>(
148→      `SELECT evidence_enforcement, min_evidence_age_minutes, evidence_enforcement_threshold FROM $ws;`,
149→      { ws: workspaceRecord },
150→    );
151→    evidenceEnforcementMode =
152→      (wsRows[0]?.evidence_enforcement as EvidenceEnforcementMode) ?? "bootstrap";
153→    minEvidenceAgeMinutes = wsRows[0]?.min_evidence_age_minutes;
154→
155→    // Lazy maturity evaluation (WD-08): check if bootstrap -> soft transition is warranted
156→    if (evidenceEnforcementMode === "bootstrap") {
157→      const confirmedDecisionCount = await countConfirmedDecisions(deps.surreal, workspaceRecord);
158→      if (shouldTransitionToSoftEnforcement({
159→        currentMode: evidenceEnforcementMode,
160→        confirmedDecisionCount,
161→      })) {
162→        const transitioned = await transitionEnforcementToSoft(deps.surreal, workspaceRecord);
163→        if (transitioned) {
164→          evidenceEnforcementMode = "soft";
165→        }
166→      }
