117→// --- Policy Evidence Requirements Evaluation ---
118→
119→type PolicyEvidenceEvaluation = {
120→  met: boolean;
121→  warnings: string[];
122→};
123→
124→/**
125→ * Evaluates whether the provided evidence meets policy-defined requirements.
126→ * Pure function -- no IO.
127→ */
128→export function evaluatePolicyEvidenceRequirements(
129→  requirements: PolicyEvidenceRequirements,
130→  evidenceCount: number,
131→  verifiedTableCounts?: Record<string, number>,
132→): PolicyEvidenceEvaluation {
133→  const warnings: string[] = [];
134→  let met = true;
135→
136→  if (evidenceCount < requirements.min_count) {
137→    warnings.push(
138→      `Policy requires at least ${requirements.min_count} evidence references but only ${evidenceCount} were provided`,
139→    );
140→    met = false;
141→  }
142→
143→  if (requirements.required_types && verifiedTableCounts) {
144→    for (const requiredType of requirements.required_types) {
145→      if ((verifiedTableCounts[requiredType] ?? 0) === 0) {
146→        warnings.push(
147→          `Policy requires at least one ${requiredType} evidence reference`,
148→        );
149→        met = false;
150→      }
151→    }
152→  }
153→
154→  return { met, warnings };
155→}
