159→export async function evaluateIntent(
160→  input: EvaluateIntentInput,
161→): Promise<EvaluationOutput> {
162→  const intentContext: IntentEvaluationContext = {
163→    goal: input.intent.goal,
164→    reasoning: input.intent.reasoning,
165→    priority: input.intent.priority ?? 0,
166→    action_spec: input.intent.action_spec,
167→    budget_limit: input.intent.budget_limit,
168→    requester_type: input.requesterType,
169→    requester_role: input.requesterRole,
170→  };
171→
172→  const gateResult = await evaluatePolicyGate(
173→    input.surreal,
174→    input.identityId,
175→    input.workspaceId,
176→    intentContext,
177→  );
178→
179→  if (!gateResult.passed) {
180→    return {
181→      decision: "REJECT",
182→      risk_score: 0,
183→      reason: gateResult.reason,
184→      policy_only: true,
185→      policy_trace: gateResult.policy_trace,
186→      human_veto_required: false,
187→    };
188→  }
189→
190→  // Human veto exists so a person can review agent actions. When the
191→  // requester IS a human the veto requirement is inherently satisfied.
192→  const humanVetoRequired =
193→    gateResult.human_veto_required && input.requesterType !== "human";
194→  const policyTrace = gateResult.policy_trace;
195→
196→  // --- Evidence verification step (after policy gate, before LLM) ---
197→  let evidenceVerification: EvidenceVerificationResult | undefined;
198→  const enforcementMode = input.evidenceEnforcementMode ?? "bootstrap";
199→
200→  if (input.evidenceRefs && input.evidenceRefs.length > 0) {
201→    evidenceVerification = await verifyEvidence(
202→      input.surreal,
203→      input.evidenceRefs,
204→      input.workspaceId,
205→      enforcementMode,
206→      input.intentCreatedAt,
207→      input.intent.priority,
208→      input.requesterAgent,
209→      input.minEvidenceAgeMinutes,
210→    );
211→  } else {
212→    // No evidence provided -- record that fact
213→    evidenceVerification = {
214→      verified_count: 0,
215→      total_count: 0,
216→      verification_time_ms: 0,
217→      enforcement_mode: enforcementMode,
218→    };
219→  }
220→
221→  // --- Policy evidence requirements gate (after verification, before LLM) ---
222→  const policyEvidenceRequirements = gateResult.evidence_requirements;
223→  if (policyEvidenceRequirements && enforcementMode === "hard") {
224→    const evidenceCount = input.evidenceRefs?.length ?? 0;
225→    const policyEval = evaluatePolicyEvidenceRequirements(
226→      policyEvidenceRequirements,
227→      evidenceCount,
228→    );
229→
230→    if (!policyEval.met) {
231→      // Merge policy warnings into evidence verification
232→      const mergedVerification: EvidenceVerificationResult = {
233→        ...evidenceVerification!,
234→        warnings: [
235→          ...(evidenceVerification?.warnings ?? []),
236→          ...policyEval.warnings,
237→        ],
238→      };
239→
240→      return {
241→        decision: "REJECT",
242→        risk_score: 0,
243→        reason: `Policy evidence requirement not met: ${policyEval.warnings[0]}`,
244→        policy_only: false,
245→        policy_trace: policyTrace,
246→        human_veto_required: false,
247→        evidence_verification: mergedVerification,
248→        hard_enforcement_rejection: true,
249→      };

