 31→// ---------------------------------------------------------------------------
 32→// Pure: Parse a single evidence reference string
 33→// ---------------------------------------------------------------------------
 34→
 35→export function parseEvidenceRef(ref: string): ParsedEvidenceRef | undefined {
 36→  const colonIndex = ref.indexOf(":");
 37→  if (colonIndex <= 0 || colonIndex === ref.length - 1) return undefined;
 38→
 39→  const table = ref.slice(0, colonIndex);
 40→  const rawId = stripRecordIdEscaping(ref.slice(colonIndex + 1));
 41→
 42→  if (!EVIDENCE_TABLE_ALLOWLIST.has(table)) return undefined;
 43→
 44→  return { table, id: rawId, record: new RecordId(table, rawId) };
 45→}
