 47→// ---------------------------------------------------------------------------
 48→// Pure: Parse all evidence refs, collecting valid and invalid
 49→// ---------------------------------------------------------------------------
 50→
 51→export function parseAllEvidenceRefs(
 52→  refs: ReadonlyArray<string | RecordId>,
 53→): { parsed: ParsedEvidenceRef[]; invalidRefs: string[] } {
 54→  const parsed: ParsedEvidenceRef[] = [];
 55→  const invalidRefs: string[] = [];
 56→
 57→  for (const ref of refs) {
 58→    if (typeof ref === "object" && ref !== null && "table" in ref) {
 59→      // Already a RecordId
 60→      const table = ref.table.name;
 61→      const id = ref.id as string;
 62→      if (EVIDENCE_TABLE_ALLOWLIST.has(table)) {
 63→        parsed.push({ table, id, record: ref as RecordId });
 64→      } else {
 65→        invalidRefs.push(`${table}:${id}`);
 66→      }
 67→    } else {
 68→      const result = parseEvidenceRef(String(ref));
 69→      if (result) {
 70→        parsed.push(result);
 71→      } else {
 72→        invalidRefs.push(String(ref));
 73→      }
 74→    }
 75→  }
 76→
 77→  return { parsed, invalidRefs };
 78→}
