139→export async function updateIntentStatus(
140→  surreal: Surreal,
141→  intentId: string,
142→  newStatus: IntentStatus,
143→  updates?: StatusUpdateFields,
144→): Promise<{ ok: true; record: IntentRecord } | { ok: false; error: string }> {
145→  const existing = await getIntentById(surreal, intentId);
146→  if (!existing) {
147→    return { ok: false, error: `Intent ${intentId} not found` };
148→  }
149→
150→  const transition = transitionStatus(existing.status, newStatus);
151→  if (!transition.ok) {
152→    return { ok: false, error: transition.error };
153→  }
154→
155→  const record = new RecordId("intent", intentId);
156→  const now = new Date();
157→
158→  const setFields: Record<string, unknown> = {
159→    status: newStatus,
160→    updated_at: now,
161→  };
162→
163→  if (updates?.evaluation) {
164→    setFields.evaluation = updates.evaluation;
165→  }
166→  if (updates?.veto_expires_at) {
167→    setFields.veto_expires_at = updates.veto_expires_at;
168→  }
169→  if (updates?.veto_reason) {
170→    setFields.veto_reason = updates.veto_reason;
171→  }
172→  if (updates?.error_reason) {
173→    setFields.error_reason = updates.error_reason;
174→  }
175→  if (updates?.evidence_verification) {
176→    setFields.evidence_verification = updates.evidence_verification;
177→  }
178→
179→  const [rows] = await surreal.query<[IntentRecord[]]>(
180→    "UPDATE $record MERGE $fields RETURN AFTER;",
181→    {
182→      record,
183→      fields: setFields,
184→    },
185→  );
186→
187→  return { ok: true, record: rows[0] };
188→}
