197→// ---------------------------------------------------------------------------
198→// Pure: Count independent authors (not the requester)
199→// ---------------------------------------------------------------------------
200→
201→/**
202→ * Counts distinct authors of evidence that are not the requesting agent.
203→ *
204→ * Uses `source_agent` field on query rows. Rows where `source_agent` matches
205→ * the requester are excluded. Rows without `source_agent` (entity types like
206→ * decisions or tasks that lack explicit authorship tracking) are treated as
207→ * independently authored -- the absence of authorship attribution means
208→ * we cannot prove the requester created them.
209→ *
210→ * Returns the count of distinct non-requester authors. Entities with unknown
211→ * authorship each count as a separate anonymous author.
212→ */
213→export function countIndependentAuthors(
214→  queryRows: ReadonlyArray<EvidenceQueryRow>,
215→  requesterAgent: string,
216→): number {
217→  const independentAuthors = new Set<string>();
218→  let anonymousCount = 0;
219→
220→  for (const row of queryRows) {
221→    if (!row.source_agent) {
222→      // Entity without authorship tracking -- treated as independent
223→      anonymousCount++;
224→      continue;
225→    }
226→    if (row.source_agent !== requesterAgent) {
227→      independentAuthors.add(row.source_agent);
228→    }
229→  }
230→
231→  return independentAuthors.size + anonymousCount;
232→}
