235→// Pure: Evaluate risk-tiered evidence requirements
236→// ---------------------------------------------------------------------------
237→
238→type RiskTierInput = {
239→  riskScore: number;
240→  verifiedCount: number;
241→  verifiedTableCounts: Record<string, number>;
242→  independentAuthorCount: number;
243→};
244→
245→type RiskTierResult = {
246→  tierMet: boolean;
247→  warnings: string[];
248→};
249→
250→/**
251→ * Evaluates whether evidence meets the requirements for the intent's risk tier.
252→ *
253→ * Risk tiers:
254→ * - Low (0-30):    1+ ref any type, 0 independent authors required
255→ * - Medium (31-70): 2+ refs with decision or task, 1+ independent author
256→ * - High (71-100):  3+ refs with decision AND (task or observation), 2+ independent authors
257→ */
258→export function evaluateRiskTierRequirements(input: RiskTierInput): RiskTierResult {
259→  const { riskScore, verifiedCount, verifiedTableCounts, independentAuthorCount } = input;
260→  const warnings: string[] = [];
261→
262→  if (riskScore <= 30) {
263→    // Low risk: 1 ref any type, no independent authors required
264→    if (verifiedCount < 1) {
265→      warnings.push("Low-risk tier requires at least 1 verified evidence reference");
266→      return { tierMet: false, warnings };
267→    }
268→    return { tierMet: true, warnings };
269→  }
270→
271→  if (riskScore <= 70) {
272→    // Medium risk: 2+ refs with decision or task, 1 independent author
273→    let met = true;
274→    if (verifiedCount < 2) {
275→      warnings.push("Medium-risk tier requires at least 2 verified evidence references");
276→      met = false;
277→    }
278→    const hasDecisionOrTask = (verifiedTableCounts.decision ?? 0) > 0
279→      || (verifiedTableCounts.task ?? 0) > 0;
280→    if (!hasDecisionOrTask) {
281→      warnings.push("Medium-risk tier requires at least one decision or task reference");
282→      met = false;
283→    }
284→    if (independentAuthorCount < 1) {
285→      warnings.push("Medium-risk tier requires at least 1 independent author");
286→      met = false;
287→    }
288→    return { tierMet: met, warnings };
289→  }

