345→// ---------------------------------------------------------------------------
346→// Effect Boundary: Batch query SurrealDB for evidence existence + scope
347→// ---------------------------------------------------------------------------
348→
349→async function batchQueryEvidence(
350→  surreal: Surreal,
351→  parsedRefs: ParsedEvidenceRef[],
352→): Promise<EvidenceQueryRow[]> {
353→  if (parsedRefs.length === 0) return [];
354→
355→  // SurrealDB does not support SELECT FROM $array where $array is an array
356→  // of RecordIds (throws "Specify a database to use"). Use per-ref SELECT
357→  // statements combined in a single .query() call for one round-trip.
358→  const statements = parsedRefs.map((_, i) => `SELECT id, workspace, status, created_at, source_agent FROM $r${i};`).join(" ");
359→  const bindings: Record<string, RecordId> = {};
360→  for (let i = 0; i < parsedRefs.length; i++) {
361→    bindings[`r${i}`] = parsedRefs[i].record;
362→  }
363→
364→  const results = await surreal.query(statements, bindings);
365→
366→  // Each statement returns an array; flatten all results
367→  const rows: EvidenceQueryRow[] = [];
368→  for (const result of results as Array<EvidenceQueryRow[]>) {
369→    if (Array.isArray(result)) {
370→      rows.push(...result);
371→    }
372→  }
373→
374→  return rows;
375→}
