381→export async function verifyEvidence(
382→  surreal: Surreal,
383→  evidenceRefs: ReadonlyArray<string | RecordId>,
384→  workspaceId: RecordId<"workspace">,
385→  enforcementMode: EvidenceEnforcementMode,
386→  intentCreatedAt?: Date,
387→  riskScore?: number,
388→  requesterAgent?: string,
389→  minEvidenceAgeMinutes?: number,
390→): Promise<EvidenceVerificationResult> {
391→  const startMs = performance.now();
392→
393→  // Pure: parse refs
394→  const { parsed, invalidRefs } = parseAllEvidenceRefs(evidenceRefs);
395→
396→  // Collect warnings from invalid refs
397→  const warnings: string[] = invalidRefs.map(
398→    (ref) => `${ref} is not a valid evidence reference`,
399→  );
400→
401→  // Effect boundary: single batched DB query
402→  const queryRows = await batchQueryEvidence(surreal, parsed);
403→
404→  // Pure: classify results
405→  const classificationOptions: ClassificationOptions = {
406→    ...(minEvidenceAgeMinutes ? { minEvidenceAgeMinutes } : {}),
407→  };
408→  const classification = classifyQueryResults(parsed, queryRows, workspaceId, intentCreatedAt, classificationOptions);
409→
410→  // Pure: authorship independence check
411→  const independentAuthorCount = requesterAgent
412→    ? countIndependentAuthors(queryRows, requesterAgent)
413→    : undefined;
414→
415→  // Pure: risk-tier evaluation
416→  let tierResult: RiskTierResult | undefined;
417→  if (riskScore !== undefined && independentAuthorCount !== undefined) {
418→    tierResult = evaluateRiskTierRequirements({
419→      riskScore,
420→      verifiedCount: classification.verifiedCount,
421→      verifiedTableCounts: classification.verifiedTableCounts,
422→      independentAuthorCount,
423→    });
424→  }
425→
426→  const allWarnings = [
427→    ...classification.warnings,
428→    ...warnings,
429→    ...(tierResult?.warnings ?? []),
430→  ];
431→
432→  const elapsedMs = Math.max(1, Math.ceil(performance.now() - startMs));
433→
434→  // Pure: build final result
435→  return buildVerificationResult({
436→    verifiedCount: classification.verifiedCount,
437→    totalCount: evidenceRefs.length,
438→    failedRefs: [...classification.failedRefs, ...invalidRefs],
439→    warnings: allWarnings,
440→    verificationTimeMs: elapsedMs,
441→    enforcementMode,
442→    independentAuthorCount,
443→    tierMet: tierResult?.tierMet,
444→  });
445→}
